```dart
final router = GoRouter(
  redirect: (context, state) {
    final isLoggedIn = AuthService.isLoggedIn; // variable globale ou provider
    final isGoingToLogin = state.matchedLocation == '/login';

    if (!isLoggedIn && !isGoingToLogin) {
      return '/login';
    }
    if (isLoggedIn && isGoingToLogin) {
      return '/';
    }
    return null; // pas de redirection
  },
  routes: [
    GoRoute(path: '/', builder: (context, state) => HomeScreen()),
    GoRoute(path: '/profil', builder: (context, state) => ProfilScreen()),
    GoRoute(path: '/login', builder: (context, state) => LoginScreen()),
  ],
);
```

Il faut utiliser le paramètre `pageBuilder` au lieu de `builder` dans GoRoute. `pageBuilder` retourne un `Page<void>` (ex. `CustomTransitionPage`).
Exemple :
```dart
GoRoute(
  path: '/settings',
  pageBuilder: (context, state) => CustomTransitionPage(
    child: SettingsScreen(),
    transitionsBuilder: (context, animation, secondaryAnimation, child) {
      return FadeTransition(opacity: animation, child: child);
    },
  ),
)
```
